import { findClosestThemeProvider } from './DomUtil';
/**
 * Utility class for components that need to react to theme provider changes
 * and OS color scheme changes. Handles both FAST and Lit components.
 */
export class ThemeReactive {
    constructor(hostElement) {
        this.hostElement = hostElement;
        this.themeProvider = null;
        this.callbacks = new Set();
        this.mutationObserver = null;
        this.isConnected = false;
        this.handleOsThemeChange = () => {
            if (this.getThemeInfo().isAutomatic) {
                this.notifyCallbacks();
            }
        };
        this.osMediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
        this.handleOsThemeChange = this.handleOsThemeChange.bind(this);
    }
    /**
     * Start listening for theme changes. Call this in connectedCallback.
     */
    connect() {
        if (this.isConnected)
            return;
        this.isConnected = true;
        this.themeProvider = this.findThemeProvider();
        if (this.themeProvider) {
            // Listen for theme provider attribute changes
            this.mutationObserver = new MutationObserver(() => this.notifyCallbacks());
            this.mutationObserver.observe(this.themeProvider, {
                attributes: true,
                attributeFilter: ['theme', 'automatic'],
            });
        }
        // Listen for OS theme changes
        this.osMediaQuery.addEventListener('change', this.handleOsThemeChange);
    }
    /**
     * Stop listening for theme changes. Call this in disconnectedCallback.
     */
    disconnect() {
        if (!this.isConnected)
            return;
        this.isConnected = false;
        this.osMediaQuery.removeEventListener('change', this.handleOsThemeChange);
        if (this.mutationObserver) {
            this.mutationObserver.disconnect();
            this.mutationObserver = null;
        }
        this.themeProvider = null;
    }
    /**
     * Add a callback to be notified when theme changes
     */
    onThemeChange(callback) {
        this.callbacks.add(callback);
        return () => this.callbacks.delete(callback); // Return unsubscribe function
    }
    /**
     * Get current theme information
     */
    getThemeInfo() {
        const themeProvider = this.getThemeProvider();
        const automaticAttr = themeProvider.getAttribute('automatic');
        const isAutomatic = automaticAttr === 'true' || automaticAttr === '';
        const theme = themeProvider.getAttribute('theme');
        return {
            isDarkMode: isAutomatic ? this.osMediaQuery.matches : theme === 'dark',
            isHighContrast: theme === 'high-contrast',
            isAutomatic,
            theme,
        };
    }
    /**
     * Convenience method to check if current theme is dark mode
     */
    isDarkMode() {
        return this.getThemeInfo().isDarkMode;
    }
    /**
     * Convenience method to check if current theme is high contrast
     */
    isHighContrast() {
        return this.getThemeInfo().isHighContrast;
    }
    /**
     * Get the theme provider element
     */
    getThemeProvider() {
        if (!this.themeProvider) {
            this.themeProvider = this.findThemeProvider();
        }
        if (!this.themeProvider) {
            throw new Error(`${this.hostElement.tagName?.toLowerCase() || 'Component'} requires a chameleon-theme-provider element`);
        }
        return this.themeProvider;
    }
    findThemeProvider() {
        return findClosestThemeProvider(this.hostElement) || null;
    }
    notifyCallbacks() {
        this.callbacks.forEach((callback) => {
            callback();
        });
    }
}
