import { forwardRef } from 'react';
import { createReactWrapper } from '../common/PrefixUtils';
export const Typography = forwardRef(({ children, gutterBottom, gutterTop, lineClamp, ...props }, ref) => createReactWrapper({
    tagName: 'chameleon-typography',
    props: {
        ...props,
        'gutter-bottom': gutterBottom,
        'gutter-top': gutterTop,
        'line-clamp': lineClamp,
        ref,
    },
    children,
}));
