import { DesignSystem, } from '@microsoft/fast-foundation';
import { chameleonDesignSystem } from './provideChameleonDesignSystem';
export const DEFAULT_PREFIX = 'chameleon';
export const provideChameleonDesignSystem = ({ prefix = DEFAULT_PREFIX, node, } = {}) => {
    return DesignSystem.getOrCreate(node).withPrefix(prefix);
};
export const registerFASTElements = (options, ...registryEntry) => {
    const designSystem = provideChameleonDesignSystem({ prefix: options.prefix, node: options.node });
    for (const entry of registryEntry) {
        const composedDefinition = entry({ prefix: options.prefix ?? DEFAULT_PREFIX });
        const tagName = `${composedDefinition.definition.prefix}-${composedDefinition.definition.baseName}`;
        chameleonDesignSystem.registerElement(composedDefinition.type, tagName);
        designSystem.register(composedDefinition);
    }
    return designSystem;
};
