import { html, slotted } from '@microsoft/fast-element';
/**
 * The template for the {@link @microsoft/fast-foundation#(Switch:class)} component.
 * @public
 */
export const switchTemplate = (_context, definition) => html `
    <template
        role="switch"
        aria-checked="${(x) => x.checked}"
        aria-disabled="${(x) => x.disabled}"
        tabindex="${(x) => (x.disabled ? null : 0)}"
        @keyup="${(x, c) => x.keyupHandler(c.event)}"
        @keydown="${(x, c) => x.keydownHandler(c.event)}"
        @input="${(x, c) => x.inputHandler(c.event)}"
        @click="${(x, c) => x.clickHandler(c.event)}"
        class="${(x) => (x.checked ? 'checked' : '')}"
    >
        <label
            part="label"
            class="${(x) => (x.defaultSlottedNodes?.length ? 'label' : 'label label__hidden')}"
        >
            <slot ${slotted('defaultSlottedNodes')}></slot>
        </label>
        <div part="switch" class="switch">
            <slot name="switch">${definition.switch || ''}</slot>
        </div>
        <span class="status-message" part="status-message">
            <span class="checked-message" part="checked-message">
                <slot name="checked-message"></slot>
            </span>
            <span class="unchecked-message" part="unchecked-message">
                <slot name="unchecked-message"></slot>
            </span>
        </span>
    </template>
`;
