import { SVG_GOTO_BLACK_YELLOW, SVG_GOTO_WHITE_YELLOW } from '@getgo/chameleon-icons';
import { unsafeCSS } from 'lit';
import { unsafeSVG } from 'lit/directives/unsafe-svg.js';
import { html, unsafeStatic } from 'lit/static-html.js';
import { ChameleonLitElement } from '../common/ChameleonLitElement';
import { ThemeReactive } from '../common/utils/ThemeReactive';
import { tagFor } from '../provideChameleonDesignSystem';
import { SvgComponent } from '../Svg';
import styles from './LaunchScreen.styles.scss';
/**
 * A launch screen component with animated GoTo logo that adapts to theme.
 *
 * @slot - Override animated logomark
 */
export class LaunchScreenComponent extends ChameleonLitElement {
    connectedCallback() {
        super.connectedCallback();
        this.themeReactive = new ThemeReactive(this);
        this.themeReactive.onThemeChange(() => {
            this.requestUpdate();
        });
        this.themeReactive.connect();
    }
    disconnectedCallback() {
        super.disconnectedCallback();
        this.themeReactive?.disconnect();
    }
    render() {
        const svgTag = unsafeStatic(tagFor(SvgComponent));
        const themeInfo = this.themeReactive?.getThemeInfo() || { isDarkMode: false, isHighContrast: false };
        return html `
      <slot>
      ${themeInfo.isDarkMode || themeInfo.isHighContrast
            ? html `<${svgTag}>${unsafeSVG(SVG_GOTO_WHITE_YELLOW)}</${svgTag}>`
            : html `<${svgTag}>${unsafeSVG(SVG_GOTO_BLACK_YELLOW)}</${svgTag}>`}
      </slot>
    `;
    }
}
LaunchScreenComponent.baseName = 'launch-screen';
LaunchScreenComponent.styles = unsafeCSS(styles);
