export class ButtonActivationController {
    constructor(host, shouldBlockActivation) {
        this.host = host;
        this.shouldBlockActivation = shouldBlockActivation;
        this.activationListener = (event) => {
            if (this.shouldBlockActivation(event)) {
                event.preventDefault();
                event.stopPropagation();
            }
        };
        this.host.addController(this);
    }
    hostConnected() {
        this.host.addEventListener('click', this.activationListener, { capture: true });
    }
    hostDisconnected() {
        this.host.removeEventListener('click', this.activationListener, { capture: true });
    }
}
