import { html } from '@microsoft/fast-element';
import { ButtonLinkComponent, buttonLinkTemplate } from './ButtonLink';
import { SVG_EXTERNAL_LINK_OUTLINED } from '@getgo/chameleon-icons';
import styles from './ButtonLink.styles.scss';
import { withStylePrefix } from '../common/withStylePrefix';
import { SvgComponent } from '../Svg';
import { tagFor } from '../provideChameleonDesignSystem';
export const chameleonButtonLink = ButtonLinkComponent.compose({
    baseName: 'button-link',
    template: buttonLinkTemplate,
    styles: withStylePrefix(styles),
    shadowOptions: {
        delegatesFocus: true,
    },
    end: (() => {
        const svgTag = tagFor(SvgComponent);
        return html `<${svgTag}>${SVG_EXTERNAL_LINK_OUTLINED}</${svgTag}>`;
    }),
});
