import { html, slotted } from '@microsoft/fast-element';
export const checkboxTemplate = (_context, definition) => html `
    <template
      role="checkbox"
      aria-checked="${(x) => (x.indeterminate ? 'mixed' : x.checked ? 'true' : 'false')}"
      aria-required="${(x) => x.required}"
      aria-disabled="${(x) => x.disabled}"
      tabindex="${(x) => (!x.disabled ? 0 : void 0)}"
      @click="${(x, c) => x.clickHandler(c.event)}"
      @input="${(x, c) => x.inputHandler(c.event)}"
      @keydown="${(x, c) => x.keydownHandler(c.event)}"
      @keyup="${(x, c) => x.keyupHandler(c.event)}"
      class="${(x) => (x.checked ? 'checked' : '')} ${(x) => (x.indeterminate ? 'indeterminate' : '')}"
    >
      <div part="control" class="control">
        <slot name="checked-indicator">
          ${definition.checkedIndicator || ''}
        </slot>
        <slot name="indeterminate-indicator">
          ${definition.indeterminateIndicator || ''}
        </slot>
      </div>
      <label
        part="label"
        class="${(x) => (x.defaultSlottedNodes?.length ? 'label' : 'label label__hidden')}"
      >
        <slot ${slotted('defaultSlottedNodes')}></slot>
      </label>
    </template>
  `;
