import { html, ref } from '@microsoft/fast-element';
/**
 * The template for the end element.
 * For use with {@link StartEnd}
 *
 * @public
 */
export const endSlotTemplate = (_context, definition) => html `
    <span
        part="end"
        ${ref('endContainer')}
        class=${(_x) => (definition.end ? 'end' : void 0)}
    >
        <slot name="end" ${ref('end')} @slotchange="${(x) => x.handleEndContentChange()}">
            ${definition.end || ''}
        </slot>
    </span>
`;
/**
 * The template for the start element.
 * For use with {@link StartEnd}
 *
 * @public
 */
export const startSlotTemplate = (_context, definition) => html `
    <span
        part="start"
        ${ref('startContainer')}
        class="${(_x) => (definition.start ? 'start' : void 0)}"
    >
        <slot
            name="start"
            ${ref('start')}
            @slotchange="${(x) => x.handleStartContentChange()}"
        >
            ${definition.start || ''}
        </slot>
    </span>
`;
