export function makeNumberRowField(field) {
    const fieldOffset = (field.indexOfAnchorInRow % field.rowLength) - (field.anchor % field.rowLength);
    return {
        getRowFor: (number) => {
            const numberAtIndex0 = number - ((number + fieldOffset) % field.rowLength);
            return [...new Array(field.rowLength).keys()].map((i) => numberAtIndex0 + i);
        },
    };
}
