import { SVG_DOUBLE_CHEVRON_LEFT_OUTLINED, SVG_DOUBLE_CHEVRON_RIGHT_OUTLINED } from '@getgo/chameleon-icons';
import { html, slotted, when } from '@microsoft/fast-element';
import { SvgComponent } from '../Svg';
import { tagFor } from '../provideChameleonDesignSystem';
import { NavigationRailComponent } from './NavigationRail';
import styles from './NavigationRail.styles.scss';
import { NavigationRailItemComponent } from './NavigationRailItem/NavigationRailItem';
import customItemStyles from './defaultNavigationRailItemStyling.styles.scss';
// TODO: add logic with state on the SVG part of collapse button
export const chameleonNavigationRailTemplate = (_context, _definition) => {
    const svgTag = tagFor(SvgComponent);
    const navigationRailItemTag = tagFor(NavigationRailItemComponent);
    return html `
    <template
      @keydown="${(x, c) => x.handleMenuKeyDown(c.event)}"
      @focusout="${(x, c) => x.handleFocusOut(c.event)}"
      role="menu"
    >
      <div class="items">
        <slot ${slotted('items')}></slot>
      </div>
      <div style="display: ${(x) => (x.shouldDisplaySecondaryItems ? 'flex' : 'none')}" class="secondary-items">
        <slot name="secondary-items" ${slotted('secondaryItems')}></slot>
      </div>
      <${navigationRailItemTag}
        part="toggle-button"
        slot="toggle-button"
        tabindex="0"
        aria-label="${(x) => x.toggleLabel}"
        :state="${(x) => x.state}"
        @click="${(x) => x.toggle()}"
        @keyup="${(x, c) => x.handleCollapseButtonKeyup(c.event)}"
      >
        <${svgTag} slot="start">
          ${when((x) => x.state === 'expanded', html `${SVG_DOUBLE_CHEVRON_LEFT_OUTLINED}`)}
          ${when((x) => x.state === 'collapsed', html `${SVG_DOUBLE_CHEVRON_RIGHT_OUTLINED}`)}
        </${svgTag}>
        ${(x) => x.toggleLabel}
      </${navigationRailItemTag}>
    </template>
  `;
};
export const chameleonNavigationRailDefinition = {
    baseName: 'navigation-rail',
    template: chameleonNavigationRailTemplate,
    styles: `
    ${styles}
    ${customItemStyles}
  `,
    shadowOptions: {
        delegatesFocus: true,
    },
};
export const chameleonNavigationRail = NavigationRailComponent.compose(chameleonNavigationRailDefinition);
